const content = $input.first().json.choices?.[0]?.message?.content;
const parsed = typeof content === 'string' ? JSON.parse(content) : content;
const previous = $('Webhook').first().json.body.borrador || {};
const message = String($('Webhook').first().json.body.mensaje || '').toLowerCase();
const changed = new Set(Array.isArray(parsed.campos_modificados) ? parsed.campos_modificados : []);
const normalizeEmails = (items) => [...new Set((items || []).filter(correo => typeof correo === 'string' && correo.includes('@')).map(correo => correo.trim().toLowerCase()))];
const previousEmails = normalizeEmails(previous.correos);
const requestedEmails = normalizeEmails(parsed.correos);
const mentionedEmails = normalizeEmails(message.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/gi));
const hasInviteIntent = /(invita|agrega|añade|anade|participante|invitado|correo|email)/.test(message);
const clearInviteIntent = /(sin\s+(invitados?|participantes?)|elimina(r)?\s+todos\s+los\s+(invitados?|participantes?))/ .test(message);
const removeInviteIntent = /(elimina|quita|borra|remueve)/.test(message) && hasInviteIntent;
const replaceInviteIntent = /(reemplaza|sustituye|cambia\s+(los\s+)?(invitados?|participantes?)|solo\s+invita)/.test(message);
let correos = previousEmails;
if (clearInviteIntent) {
  correos = [];
} else if (removeInviteIntent && mentionedEmails.length) {
  correos = previousEmails.filter(correo => !mentionedEmails.includes(correo));
} else if (hasInviteIntent && (mentionedEmails.length || requestedEmails.length)) {
  const incoming = mentionedEmails.length ? mentionedEmails : requestedEmails;
  correos = replaceInviteIntent ? incoming : normalizeEmails([...previousEmails, ...incoming]);
}

const choose = (field, fallback) => {
  if (!previous[field] || changed.has(field)) return parsed[field] ?? fallback;
  return previous[field];
};
const meeting = {
  tema: choose('tema', 'Reunión sin tema'),
  fecha_inicio: choose('fecha_inicio', null),
  duracion_minutos: Number(choose('duracion_minutos', 60)) || 60,
  tipo: ['virtual', 'presencial', 'mixta'].includes(choose('tipo', 'virtual')) ? choose('tipo', 'virtual') : 'virtual',
  direccion: changed.has('direccion') ? (parsed.direccion || null) : (previous.direccion || null),
  correos
};

if (!meeting.fecha_inicio) throw new Error('No se pudo determinar la fecha de la reunión');

return [{
  json: {
    estado: 'borrador',
    respuesta: 'Borrador actualizado. Confírmalo cuando esté listo.',
    meeting,
    destinatarios: correos.map(correo => ({ correo, rol: 'participante' }))
  }
}];
